bool test(char par){ 
    if(par == 'a' || par == 'e' || par == 'i' || par == 'o' || par == 'u'){
        return true;
    }
    return false;
}
class Solution {
public:
    int maxVowels(string s, int k) {
        int pts = 0;
        for(int i = 0; i < k; i++){
            if(test(s[i]))
                pts++;
        }

        int max = pts;
        for(int i = k; i < s.size(); i++){
            if(test(s[i -k]))
                pts--;
            if(test(s[i]))
                pts++;
            max = std::max(max, pts);
        }


        return max;
    }
};
